  var STATION_NAMES = { a: "Task 1 · Read the data", b: "Task 2 · The policy timeline", c: "Task 3 · The pyramid lab", d: "Task 4 · Match the evidence", e: "Task 5 · Weigh the evidence", v: "Final call · Your verdict" };
  var TOTAL_MAX = 34;

  /* ================= Utilities ================= */

